/**
 * A node in the custom renderer UI tree. Can be nested recursively via the
 * `children` field of each [`Component`].
 */
export type CustomRendererNode =
  /** Empty node. */
  | { tag: "Nil"; value: undefined }
  /** Raw text string. */
  | { tag: "String"; value: string }
  /** Generic container. */
  | { tag: "Box"; value: Component<BoxProps> }
  /** Vertical layout. */
  | { tag: "Column"; value: Component<ColumnProps> }
  /** Horizontal layout. */
  | { tag: "Row"; value: Component<RowProps> }
  /** Flexible space. */
  | { tag: "Spacer"; value: Component<undefined> }
  /** Text display. */
  | { tag: "Text"; value: Component<TextProps> }
  /** Interactive button. */
  | { tag: "Button"; value: Component<ButtonProps> }
  /** Text input. */
  | { tag: "TextField"; value: Component<TextFieldProps> };

export const CustomRendererNode: S.Codec<CustomRendererNode> = S.lazy(
  (): S.Codec<CustomRendererNode> =>
    S.taggedUnion({
      Nil: S.unit,
      String: S.str,
      Box: Component(BoxProps),
      Column: Component(ColumnProps),
      Row: Component(RowProps),
      Spacer: Component(S.unit),
      Text: Component(TextProps),
      Button: Component(ButtonProps),
      TextField: Component(TextFieldProps),
    }),
);

