/** Layout and styling modifiers applied to custom renderer components. */
export type Modifier =
  /** Outer spacing. */
  | { tag: "Margin"; value: Dimensions }
  /** Inner spacing. */
  | { tag: "Padding"; value: Dimensions }
  /** Background fill. */
  | { tag: "Background"; value: Background }
  /** Border style. */
  | { tag: "Border"; value: BorderStyle }
  /** Fixed height. */
  | { tag: "Height"; value: Size }
  /** Fixed width. */
  | { tag: "Width"; value: Size }
  /** Minimum width. */
  | { tag: "MinWidth"; value: Size }
  /** Minimum height. */
  | { tag: "MinHeight"; value: Size }
  /** Fill available width. */
  | { tag: "FillWidth"; value: boolean }
  /** Fill available height. */
  | { tag: "FillHeight"; value: boolean };

export const Modifier: S.Codec<Modifier> = S.lazy(
  (): S.Codec<Modifier> =>
    S.taggedUnion({
      Margin: Dimensions,
      Padding: Dimensions,
      Background: Background,
      Border: BorderStyle,
      Height: Size,
      Width: Size,
      MinWidth: Size,
      MinHeight: Size,
      FillWidth: S.bool,
      FillHeight: S.bool,
    }),
);

