/** A statement with optional proof and metadata. */
export interface Statement {
  /** Optional cryptographic proof. */
  proof?: StatementProof;
  /** Optional decryption key. */
  decryptionKey?: DecryptionKey;
  /** Optional Unix timestamp expiry. */
  expiry?: bigint;
  /** Optional channel. */
  channel?: Channel;
  /** Topic tags. */
  topics: Array<Topic>;
  /** Optional data payload. */
  data?: Bytes;
}

export const Statement: S.Codec<Statement> = S.lazy(
  (): S.Codec<Statement> =>
    S.struct({
      proof: S.option(StatementProof),
      decryptionKey: S.option(DecryptionKey),
      expiry: S.option(S.u64),
      channel: S.option(Channel),
      topics: S.vec(Topic),
      data: S.option(Bytes),
    }) as S.Codec<Statement>,
);

/** Cryptographic proof for a statement. */
export type StatementProof =
  /** Sr25519 signature proof. */
  | { tag: "Sr25519"; value: { signature: Uint8Array; signer: Uint8Array } }
  /** Ed25519 signature proof. */
  | { tag: "Ed25519"; value: { signature: Uint8Array; signer: Uint8Array } }
  /** ECDSA signature proof. */
  | { tag: "Ecdsa"; value: { signature: Uint8Array; signer: Uint8Array } }
  /** On-chain event proof. */
  | {
      tag: "OnChain";
      value: { who: Uint8Array; blockHash: Uint8Array; event: bigint };
    };

export const StatementProof: S.Codec<StatementProof> = S.lazy(
  (): S.Codec<StatementProof> =>
    S.taggedUnion({
      Sr25519: S.struct({
        signature: S.byteArray(64),
        signer: S.byteArray(32),
      }) as S.Codec<{ signature: Uint8Array; signer: Uint8Array }>,
      Ed25519: S.struct({
        signature: S.byteArray(64),
        signer: S.byteArray(32),
      }) as S.Codec<{ signature: Uint8Array; signer: Uint8Array }>,
      Ecdsa: S.struct({
        signature: S.byteArray(65),
        signer: S.byteArray(33),
      }) as S.Codec<{ signature: Uint8Array; signer: Uint8Array }>,
      OnChain: S.struct({
        who: S.byteArray(32),
        blockHash: S.byteArray(32),
        event: S.u64,
      }) as S.Codec<{ who: Uint8Array; blockHash: Uint8Array; event: bigint }>,
    }),
);

/** Statement proof creation error. */
export type StatementProofError =
  /** Signing operation failed. */
  | { tag: "UnableToSign"; value: undefined }
  /** Account not recognized. */
  | { tag: "UnknownAccount"; value: undefined }
  /** Catch-all. */
  | { tag: "Unknown"; value: { reason: string } };

export const StatementProofError: S.Codec<StatementProofError> = S.lazy(
  (): S.Codec<StatementProofError> =>
    S.taggedUnion({
      UnableToSign: S.unit,
      UnknownAccount: S.unit,
      Unknown: S.struct({ reason: S.str }) as S.Codec<{ reason: string }>,
    }),
);

